import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { AlignCenter, AlignLeft, AlignRight } from "lucide-react";
import { useEditor } from "novel";

export const TextAlignmentButtons = () => {
  const { editor } = useEditor();
  if (!editor) return null;

  const alignmentItems = [
    {
      name: "align-left",
      icon: AlignLeft,
      command: () => editor.chain().focus().setTextAlign("left").run(),
      isActive: () => editor.isActive({ textAlign: "left" }),
    },
    {
      name: "align-center",
      icon: AlignCenter,
      command: () => editor.chain().focus().setTextAlign("center").run(),
      isActive: () => editor.isActive({ textAlign: "center" }),
    },
    {
      name: "align-right",
      icon: AlignRight,
      command: () => editor.chain().focus().setTextAlign("right").run(),
      isActive: () => editor.isActive({ textAlign: "right" }),
    },
  ];

  return (
    <div className="flex">
      {alignmentItems.map((item) => (
        <Button
          key={item.name}
          size="icon"
          variant="ghost"
          onClick={item.command}
          className={cn(
            "rounded-none h-8",
            { "text-primary": item.isActive() } // active state
          )}
        >
          <item.icon className="h-4 w-4" />
        </Button>
      ))}
    </div>
  );
};

import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import {
  BoldIcon,
  CodeIcon,
  ItalicIcon,
  StrikethroughIcon,
  UnderlineIcon
} from 'lucide-react'
import { EditorBubbleItem, useEditor } from 'novel'
import type { SelectorItem } from './node-selector'

export const TextButtons = () => {
  const { editor } = useEditor()
  if (!editor) return null
  const items: SelectorItem[] = [
    {
      name: 'bold',
      isActive: editor => (editor ? editor.isActive('bold') : false),
      command: editor => editor?.chain().focus().toggleBold().run(),
      icon: BoldIcon
    },
    {
      name: 'italic',
      isActive: editor => (editor ? editor.isActive('italic') : false),
      command: editor => editor?.chain().focus().toggleItalic().run(),
      icon: ItalicIcon
    },
    {
      name: 'underline',
      isActive: editor => (editor ? editor.isActive('underline') : false),
      command: editor => editor?.chain().focus().toggleUnderline().run(),
      icon: UnderlineIcon
    },
    {
      name: 'strike',
      isActive: editor => (editor ? editor.isActive('strike') : false),
      command: editor => editor?.chain().focus().toggleStrike().run(),
      icon: StrikethroughIcon
    },
    {
      name: 'code',
      isActive: editor => (editor ? editor.isActive('code') : false),
      command: editor => editor?.chain().focus().toggleCode().run(),
      icon: CodeIcon
    }
  ]
  return (
    <div className='flex'>
      {items.map(item => (
        <EditorBubbleItem
          key={item.name}
          onSelect={editor => {
            item.command(editor)
          }}
        >
          <Button size='sm' className='rounded-none' variant='ghost'>
            <item.icon
              className={cn('h-4 w-4', {
                'text-blue-500': item.isActive(editor)
              })}
            />
          </Button>
        </EditorBubbleItem>
      ))}
    </div>
  )
}

.ProseMirror {
  @apply p-2;
  position: relative;
}

/* Hanya tampilkan placeholder pada root p yang kosong */
.ProseMirror > p.is-editor-empty:first-child::before,
.ProseMirror > p.is-empty:not(.is-editor-empty)::before {
  content: attr(data-placeholder);
  position: absolute;
  color: hsl(var(--muted-foreground));
  pointer-events: none;
  height: 0;
}

/* Text align center - hanya untuk p langsung di bawah ProseMirror */
.ProseMirror[style*="text-align: center"] > p.is-empty::before {
  left: 50%;
  transform: translateX(-50%);
}

/* Text align right - hanya untuk p langsung di bawah ProseMirror */
.ProseMirror[style*="text-align: right"] > p.is-empty::before {
  right: 0;
}

/* Custom image styles */

.ProseMirror img {
  transition: filter 0.1s ease-in-out;

  &:hover {
    cursor: pointer;
    filter: brightness(90%);
  }

  &.ProseMirror-selectednode {
    outline: 3px solid #5abbf7;
    filter: brightness(90%);
  }
}

.img-placeholder {
  position: relative;

  &:before {
    content: "";
    box-sizing: border-box;
    position: absolute;
    top: 50%;
    left: 50%;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 3px solid var(--novel-stone-200);
    border-top-color: var(--novel-stone-800);
    animation: spinning 0.6s linear infinite;
  }
}

@keyframes spinning {
  to {
    transform: rotate(360deg);
  }
}

/* Custom TODO list checkboxes – shoutout to this awesome tutorial: https://moderncss.dev/pure-css-custom-checkbox-style/ */

ul[data-type="taskList"] li > label {
  margin-right: 0.2rem;
  user-select: none;
}

@media screen and (max-width: 768px) {
  ul[data-type="taskList"] li > label {
    margin-right: 0.5rem;
  }
}

ul[data-type="taskList"] li > label input[type="checkbox"] {
  -webkit-appearance: none;
  appearance: none;
  background-color: hsl(var(--background));
  margin: 0;
  cursor: pointer;
  width: 1.2em;
  height: 1.2em;
  position: relative;
  top: 5px;
  border: 2px solid hsl(var(--border));
  margin-right: 0.3rem;
  display: grid;
  place-content: center;

  &:hover {
    background-color: hsl(var(--accent));
  }

  &:active {
    background-color: hsl(var(--accent));
  }

  &::before {
    content: "";
    width: 0.65em;
    height: 0.65em;
    transform: scale(0);
    transition: 120ms transform ease-in-out;
    box-shadow: inset 1em 1em;
    transform-origin: center;
    clip-path: polygon(14% 44%, 0 65%, 50% 100%, 100% 16%, 80% 0%, 43% 62%);
  }

  &:checked::before {
    transform: scale(1);
  }
}

ul[data-type="taskList"] li[data-checked="true"] > div > p {
  color: var(--muted-foreground);
  text-decoration: line-through;
  text-decoration-thickness: 2px;
}

/* Overwrite tippy-box original max-width */

.tippy-box {
  max-width: 400px !important;
}

.ProseMirror:not(.dragging) .ProseMirror-selectednode {
  outline: none !important;
  background-color: var(--novel-highlight-blue);
  transition: background-color 0.2s;
  box-shadow: none;
}

